"use strict";class ProgressBar{constructor(){}static getUiElement(){return document.getElementById("fetchProgress")}static setValue(e){ProgressBar.getUiElement().value=e,ProgressBar.updateText()}static updateValue(e){ProgressBar.getUiElement().value+=e,ProgressBar.updateText()}static setMax(e){ProgressBar.getUiElement().max=e,ProgressBar.updateText()}static updateText(){let e=ProgressBar.getUiElement(),t="";1<e.max&&(t=`${e.value}/${e.max}`,ProgressBar.updateTabTitle(e.value,e.max)),document.getElementById("progressString").textContent=t}static updateTabTitle(e,t){"100.0"==(e=(100*e/t).toFixed(1))&&(e="100"),document.title=e+"% WebToEpub"}}